import "./EmployeeModal.css";
import { useState } from "react";

const EmployeeModal = ({ open, onClose, onSave }) => {

    const [formData, setFormData] = useState({
        employeeId: "",
        name: "",
        email: "",
        password: "",
        phone: "",
        department: "",
        designation: "",
        salary: "",
        joiningDate: "",
        role: "Employee",
        manager: ""
    });

    if (!open) return null;

    const handleChange = (e) => {

        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });

    };

    const handleSubmit = (e) => {

        e.preventDefault();

        onSave(formData);

    };

    return (

        <div className="modal-overlay">

            <div className="modal">

                <h2>Add Employee</h2>

                <form onSubmit={handleSubmit}>

                    <input
                        name="employeeId"
                        placeholder="Employee ID"
                        onChange={handleChange}
                        required
                    />

                    <input
                        name="name"
                        placeholder="Name"
                        onChange={handleChange}
                        required
                    />

                    <input
                        type="email"
                        name="email"
                        placeholder="Email"
                        onChange={handleChange}
                        required
                    />

                    <input
                        type="password"
                        name="password"
                        placeholder="Password"
                        onChange={handleChange}
                        required
                    />

                    <input
                        name="phone"
                        placeholder="Phone"
                        onChange={handleChange}
                        required
                    />

                    <input
                        name="department"
                        placeholder="Department"
                        onChange={handleChange}
                        required
                    />

                    <input
                        name="designation"
                        placeholder="Designation"
                        onChange={handleChange}
                        required
                    />

                    <input
                        type="number"
                        name="salary"
                        placeholder="Salary"
                        onChange={handleChange}
                        required
                    />

                    <input
                        type="date"
                        name="joiningDate"
                        onChange={handleChange}
                        required
                    />

                    <select
                        name="role"
                        onChange={handleChange}
                    >
                        <option>Employee</option>
                        <option>HR Manager</option>
                    </select>

                    <div className="modal-buttons">

                        <button
                            type="button"
                            className="cancel-btn"
                            onClick={onClose}
                        >
                            Cancel
                        </button>

                        <button type="submit">
                            Save
                        </button>

                    </div>

                </form>

            </div>

        </div>

    );

};

export default EmployeeModal;
